package com.cognizant.customer.controller;import com.cognizant.customer.model.Customer;import com.cognizant.customer.repository.CustomerRepository;import org.springframework.web.bind.annotation.*;import java.util.List;@RestController @RequestMapping("/customers") public class CustomerController{private final CustomerRepository repo;public CustomerController(CustomerRepository repo){this.repo=repo;}@GetMapping public List<Customer> all(){return repo.findAll();}@GetMapping("/{id}") public Customer one(@PathVariable Long id){return repo.findById(id).orElseThrow();}@PostMapping public Customer create(@RequestBody Customer x){return repo.save(x);}}